"""ISOCLIM application model — 8 entities with relations."""

from lof.models.gold_models import (
    GoldApplication, GoldEntity, GoldField, GoldRelation,
    GoldCapabilities, AuditConfig, NavigationConfig,
)


def make_isoclim_app() -> GoldApplication:
    return GoldApplication(
        id="isoclim",
        name="ISOCLIM",
        profile="fastapi-react",
        entities=[
            GoldEntity(
                id="client",
                name="Client",
                plural_name="Clients",
                description="Entreprise cliente",
                display_field="company_name",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="company_name", type="string", required=True,
                              searchable=True, sortable=True, max_length=200),
                    GoldField(id="email", type="email", list_visible=True),
                    GoldField(id="phone", type="phone", list_visible=True),
                    GoldField(id="siret", type="string", unique=True, max_length=14),
                    GoldField(id="address", type="text", form_visible=True,
                              list_visible=False),
                    GoldField(id="active", type="boolean", default=True, list_visible=True),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Clients", icon="building", order=10),
            ),
            GoldEntity(
                id="commande",
                name="Commande",
                plural_name="Commandes",
                description="Commande client",
                display_field="reference",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="reference", type="string", required=True,
                              searchable=True, sortable=True, max_length=50),
                    GoldField(id="description", type="text", form_visible=True,
                              list_visible=False),
                    GoldField(id="status", type="enum", default="draft",
                              list_visible=True, sortable=True),
                    GoldField(id="total_amount", type="money", list_visible=True,
                              sortable=True),
                    GoldField(id="date", type="date", default=None,
                              list_visible=True, sortable=True),
                ],
                relations=[
                    GoldRelation(id="commande_client", source="commande", target="client",
                                 kind="many-to-one", source_field="client_id",
                                 target_display_field="company_name", required=True,
                                 back_populates="client_commandes"),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Commandes", icon="file-text", order=20),
            ),
            GoldEntity(
                id="chantier",
                name="Chantier",
                plural_name="Chantiers",
                description="Chantier de construction",
                display_field="name",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="name", type="string", required=True,
                              searchable=True, sortable=True, max_length=200),
                    GoldField(id="address", type="text", form_visible=True,
                              list_visible=False),
                    GoldField(id="start_date", type="date", list_visible=True,
                              sortable=True),
                    GoldField(id="end_date", type="date", list_visible=True),
                    GoldField(id="status", type="enum", default="planned",
                              list_visible=True, sortable=True),
                ],
                relations=[
                    GoldRelation(id="chantier_commande", source="chantier", target="commande",
                                 kind="many-to-one", source_field="commande_id",
                                 target_display_field="reference", required=True,
                                 back_populates="commande_chantiers"),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Chantiers", icon="hard-hat", order=30),
            ),
            GoldEntity(
                id="equipe",
                name="Équipe",
                plural_name="Équipes",
                description="Équipe de travail",
                display_field="name",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="name", type="string", required=True,
                              searchable=True, sortable=True, max_length=100),
                    GoldField(id="description", type="text", form_visible=True,
                              list_visible=False),
                    GoldField(id="active", type="boolean", default=True, list_visible=True),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Équipes", icon="users", order=40),
            ),
            GoldEntity(
                id="employe",
                name="Employé",
                plural_name="Employés",
                description="Employé d'équipe",
                display_field="full_name",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="full_name", type="string", required=True,
                              searchable=True, sortable=True, max_length=200),
                    GoldField(id="email", type="email", list_visible=True),
                    GoldField(id="phone", type="phone", list_visible=True),
                    GoldField(id="role", type="enum", default="worker",
                              list_visible=True, sortable=True),
                    GoldField(id="active", type="boolean", default=True, list_visible=True),
                ],
                relations=[
                    GoldRelation(id="employe_equipe", source="employe", target="equipe",
                                 kind="many-to-one", source_field="equipe_id",
                                 target_display_field="name", required=True,
                                 back_populates="equipe_employes"),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Employés", icon="user", order=50),
            ),
            GoldEntity(
                id="mission",
                name="Mission",
                plural_name="Missions",
                description="Mission sur chantier",
                display_field="title",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="title", type="string", required=True,
                              searchable=True, sortable=True, max_length=200),
                    GoldField(id="description", type="text", form_visible=True,
                              list_visible=False),
                    GoldField(id="status", type="enum", default="planned",
                              list_visible=True, sortable=True),
                    GoldField(id="priority", type="enum", default="medium",
                              list_visible=True, sortable=True),
                    GoldField(id="start_date", type="date", list_visible=True),
                    GoldField(id="end_date", type="date", list_visible=True),
                    GoldField(id="blocking_reason", type="text",
                              form_visible=True, list_visible=False),
                ],
                relations=[
                    GoldRelation(id="mission_chantier", source="mission", target="chantier",
                                 kind="many-to-one", source_field="chantier_id",
                                 target_display_field="name", required=True,
                                 back_populates="chantier_missions"),
                    GoldRelation(id="mission_equipe", source="mission", target="equipe",
                                 kind="many-to-one", source_field="equipe_id",
                                 target_display_field="name", required=True,
                                 back_populates="equipe_missions"),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Missions", icon="briefcase", order=60),
            ),
            GoldEntity(
                id="equipement",
                name="Équipement",
                plural_name="Équipements",
                description="Équipement de chantier",
                display_field="name",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="name", type="string", required=True,
                              searchable=True, sortable=True, max_length=200),
                    GoldField(id="type", type="enum", default="tool",
                              list_visible=True, sortable=True),
                    GoldField(id="serial_number", type="string", unique=True,
                              list_visible=True),
                    GoldField(id="status", type="enum", default="available",
                              list_visible=True, sortable=True),
                    GoldField(id="active", type="boolean", default=True, list_visible=True),
                ],
                relations=[
                    GoldRelation(id="equipement_mission", source="equipement", target="mission",
                                 kind="many-to-one", source_field="mission_id",
                                 target_display_field="title", nullable=True,
                                 back_populates="mission_equipements"),
                ],
                capabilities=GoldCapabilities(create=True, read=True, update=True,
                                              delete=True, list=True, search=True),
                audit=AuditConfig(created_at=True, updated_at=True),
                navigation=NavigationConfig(visible=True, label="Équipements", icon="tool", order=70),
            ),
            GoldEntity(
                id="commentaire_mission",
                name="Commentaire",
                plural_name="Commentaires",
                description="Commentaire sur une mission",
                display_field="content_preview",
                fields=[
                    GoldField(id="id", type="uuid", primary=True, generated=True,
                              list_visible=False, form_visible=False),
                    GoldField(id="content", type="text", required=True,
                              form_visible=True, list_visible=False),
                    GoldField(id="author_name", type="string", required=True,
                              list_visible=True, max_length=100),
                ],
                relations=[
                    GoldRelation(id="commentaire_mission_ref", source="commentaire_mission",
                                 target="mission",
                                 kind="many-to-one", source_field="mission_id",
                                 target_display_field="title", required=True,
                                 back_populates="mission_commentaires"),
                ],
                capabilities=GoldCapabilities(create=True, read=True, delete=True,
                                              list=True, search=False, update=False),
                audit=AuditConfig(created_at=True, updated_at=False),
                navigation=NavigationConfig(visible=False),
            ),
        ],
    )
